## 代码分析 ##
    下面以 glibc 2.31 为例分析chunk的创建,释放
### malloc ###
    malloc函数实际上是__libc_malloc函数的别名
```c
void *
__libc_malloc (size_t bytes)
{
  mstate ar_ptr;
  void *victim;

  _Static_assert (PTRDIFF_MAX <= SIZE_MAX / 2,
                  "PTRDIFF_MAX is not more than half of SIZE_MAX");
   /* 当地址之间的差距不大于 size_t类型的数据所储存的最大数/2
    则报错 */
  void *(*hook) (size_t, const void *)
    = atomic_forced_read (__malloc_hook);
  if (__builtin_expect (hook != NULL, 0))
    return (*hook)(bytes, RETURN_ADDRESS (0));
  /* 检测 malloc_hook 中是否存有函数地址，
      如果有则调用指向的函数 
     在第一次调用 __libc_malloc 时,
      __malloc_hook中储存了malloc_hook_ini函数地址
      用于分配区初始化
      */

#if USE_TCACHE
  /* tcache从glibc2.26开始被使用 */

  size_t tbytes;
  if (!checked_request2size (bytes, &tbytes))
    { 
      __set_errno (ENOMEM);
      return NULL;
      /* 如果用户申请的chunk超过了可索引的地址范围
          就返回NULL 表示分配失败 */
    }
  size_t tc_idx = csize2tidx (tbytes);
   /* 获取chunk的size对应的tcache bin的编号 */
  MAYBE_INIT_TCACHE ();
   /* 检测tcache bins是否被初始化过，
        如果还未初始化tcache bins,
        则调用tcache_init函数对tcache bins进行初始化操作*/
  DIAG_PUSH_NEEDS_COMMENT;
  if (tc_idx < mp_.tcache_bins
      && tcache
      && tcache->counts[tc_idx] > 0)
    { /* 当存在对应的tcache bin，且tcache bin中存在chunk
         则直接将tcache bin中的chunk返回给用户 */
      return tcache_get (tc_idx);
    }
  DIAG_POP_NEEDS_COMMENT;
  /* 当使用了tcache bin时，先从tcache bin中获取chunk */
#endif

  if (SINGLE_THREAD_P)
    {  /* 当程序仅有一个线程时，使用_int_malloc申请chunk
          并对返回的chunk地址进行验证(创建失败 或 由mmap分配 或 由主分配区分配) */
      victim = _int_malloc (&main_arena, bytes);
      assert (!victim || chunk_is_mmapped (mem2chunk (victim)) ||
	      &main_arena == arena_for_chunk (mem2chunk (victim)));
      return victim;
    }

  arena_get (ar_ptr, bytes);
  /* 获取当前线程分配区，当当前分配区为空时，尝试使用其他分配区 */
  victim = _int_malloc (ar_ptr, bytes);

  /* 利用_int_malloc申请chunk */

  if (!victim && ar_ptr != NULL)
      /* 当无法使用当前线程分配区申请chunk时，使用其他的分配区申请chunk */
      LIBC_PROBE (memory_malloc_retry, 1, bytes);
      ar_ptr = arena_get_retry (ar_ptr, bytes);
      victim = _int_malloc (ar_ptr, bytes);
    }

  if (ar_ptr != NULL)
    __libc_lock_unlock (ar_ptr->mutex);

  assert (!victim || chunk_is_mmapped (mem2chunk (victim)) ||
          ar_ptr == arena_for_chunk (mem2chunk (victim)));
  return victim;
}
```

### malloc_hook_ini ###
```c
static void *
malloc_hook_ini (size_t sz, const void *caller)
{
  __malloc_hook = NULL;
  ptmalloc_init (); /* 初始化主分配区,初始化分配区中的bin*/
  return __libc_malloc (sz);
}
```

### _int_malloc ###
```c
static void *
_int_malloc (mstate av, size_t bytes)
{
  INTERNAL_SIZE_T nb;
  unsigned int idx;
  mbinptr bin;
  mchunkptr victim;
  INTERNAL_SIZE_T size;
  int victim_index;
  mchunkptr remainder;
  unsigned long remainder_size;
  unsigned int block;
  unsigned int bit;
  unsigned int map;
  mchunkptr fwd;
  mchunkptr bck;

#if USE_TCACHE
  size_t tcache_unsorted_count;
#endif
   /* 检测申请的chunk，因为申请chunk不只有malloc，还有calloc,realloc，
      所以在_int_malloc中再检测一次请求的大小是否合法 */

  if (!checked_request2size (bytes, &nb))
    {
      __set_errno (ENOMEM);
      return NULL;
    }

  if (__glibc_unlikely (av == NULL))
    {
      void *p = sysmalloc (nb, av);
      /* 当av==NULL时，表示没有分配区可以分配chunk了，所以需要调用sysmalloc从系统分配空间 */

      if (p != NULL)
	alloc_perturb (p, bytes); /* 初始化chunk data */
      return p;
    }
#define REMOVE_FB(fb, victim, pp)	\
  do							\
    {							\
      victim = pp;					\
      if (victim == NULL)				\
	break;						\
    }							\
  while ((pp = catomic_compare_and_exchange_val_acq (fb, victim->fd, victim)) \
	 != victim);					/* 在存在多个线程的情况下，用于取出当前bin中第一个chunk */

  if ((unsigned long) (nb) <= (unsigned long) (get_max_fast ()))
    {
      idx = fastbin_index (nb);
      mfastbinptr *fb = &fastbin (av, idx);
      mchunkptr pp;
      victim = *fb;
      if (victim != NULL)
	{
	  if (SINGLE_THREAD_P)
	    *fb = victim->fd;
	  else
	    REMOVE_FB (fb, pp, victim);
      /* 因为在符合用户申请的chunk大小的fast bin中，存在空闲chunk，
          所以直接将bin中第一个chunk返回给用户 */

	  if (__glibc_likely (victim != NULL))
	    {
	      size_t victim_idx = fastbin_index (chunksize (victim));
	      if (__builtin_expect (victim_idx != idx, 0))
		malloc_printerr ("malloc(): memory corruption (fast)");
          /* 检测bin中的chunk是否被恶意修改过 */

	      check_remalloced_chunk (av, victim, nb);
          /* 对chunk进行全面的安全检测 */

#if USE_TCACHE 
      /* 因为从fast bin中获取到的chunk大小与用户申请的chunk相同
          所以直接通过用户申请chunk大小，获取对应的tcache bin编号
          将当前fast bin中所有chunk放入tcache bin中，直到tcache bin被填满
          如果fast bin中还有chunk，就将其返回给用户 */

      /*因为这个版本fast bin的检测较多，fast bin attack 不好利用，
         可以在fast bin的开头放一个正常的chunk，修改其fd为内存中任意地址，
          然后申请一个相应大小的chunk，使正常chunk与我们想要的地址都放入tcache bin中
          因为tcache bin的检测较少，只要允许申请足够数量的chunk，
          就可以在内存中任意位置创建一个chunk

         或者在tcache bin中只剩一个空位时，将fast bin中开头的正常的chunk放入tcache bin中
          这时因为tcache bin被填满了，这时就会在内存中任意地址创建一个chunk(需要程序使用calloc) */

	      size_t tc_idx = csize2tidx (nb);
	      if (tcache && tc_idx < mp_.tcache_bins)
		{ 
		  mchunkptr tc_victim;
		  while (tcache->counts[tc_idx] < mp_.tcache_count
			 && (tc_victim = *fb) != NULL)
		    {
		      if (SINGLE_THREAD_P)

			*fb = tc_victim->fd;
		      else
			{
			  REMOVE_FB (fb, pp, tc_victim);
			  if (__glibc_unlikely (tc_victim == NULL))
			    break;
			}
		      tcache_put (tc_victim, tc_idx);
		    }
		}
#endif
	      void *p = chunk2mem (victim);
	      alloc_perturb (p, bytes);
	      return p;
	    }
	}
    }
  if (in_smallbin_range (nb))
    { /* 当用户申请的chunk大小，符合small bin的范围 */

      idx = smallbin_index (nb);
      bin = bin_at (av, idx);
      if ((victim = last (bin)) != bin)
        { /* 判断对应的small bin中是否存在chunk */
          bck = victim->bk;
	  if (__glibc_unlikely (bck->fd != victim))
	    malloc_printerr ("malloc(): smallbin double linked list corrupted");
          /* 检测双链表结构是否被破坏 */

          set_inuse_bit_at_offset (victim, nb);
          bin->bk = bck;
          bck->fd = bin;
          if (av != &main_arena)
	    set_non_main_arena (victim);
          check_malloced_chunk (av, victim, nb);
          /* 将chunk从small bin中取出 */
#if USE_TCACHE
    /* 当对应的tcache bin还没有填满，循环遍历small bin，
        直到tcache bin被填满，将剩余的第一个chunk返回给用户 */

    /* 因为small bin中存在一个双链表检测，
         所以想要通过small bin在内存中某个位置创建chunk就比较困难
         不过可以通过tcache bin，与上面fast bin的思路相同*/

	  size_t tc_idx = csize2tidx (nb);
	  if (tcache && tc_idx < mp_.tcache_bins)
	    {
	      mchunkptr tc_victim;
	      while (tcache->counts[tc_idx] < mp_.tcache_count
		     && (tc_victim = last (bin)) != bin)
		{
		  if (tc_victim != 0)
		    {
		      bck = tc_victim->bk;
		      set_inuse_bit_at_offset (tc_victim, nb);
		      if (av != &main_arena)
			set_non_main_arena (tc_victim);
		      bin->bk = bck;
		      bck->fd = bin;
		      tcache_put (tc_victim, tc_idx);
	            }
		}
	    }
#endif
          void *p = chunk2mem (victim);
          alloc_perturb (p, bytes);
          return p;
        }
    }
  else
    {
      idx = largebin_index (nb);
      /* 获取用户申请的大小对应得到large bin编号 */
      if (atomic_load_relaxed (&av->have_fastchunks))
        malloc_consolidate (av); 
      /* 合并fast bin中的chunk，并将合并后的chunk放入对应的small bin或large bin中 */
    }
#if USE_TCACHE
  INTERNAL_SIZE_T tcache_nb = 0;
  size_t tc_idx = csize2tidx (nb);
  /* 当用户申请的大小对应的tcache bin中存在chunk
      则做好准备，在大循环中尝试从tcache bin中获取chunk */
  if (tcache && tc_idx < mp_.tcache_bins)
    tcache_nb = nb;
  int return_cached = 0;
  tcache_unsorted_count = 0;
#endif
  for (;; )
    { /* 进入大循环 */
      int iters = 0;
      while ((victim = unsorted_chunks (av)->bk) != unsorted_chunks (av))
        { /* 循环遍历unsorted bin中的chunk，将其中的chunk放入对应的bin中
              当符合用户申请的条件时，尝试分裂后返回给用户 */
          bck = victim->bk;
          size = chunksize (victim);
          mchunkptr next = chunk_at_offset (victim, size);
          if (__glibc_unlikely (size <= 2 * SIZE_SZ)
              || __glibc_unlikely (size > av->system_mem))
            malloc_printerr ("malloc(): invalid size (unsorted)");
          if (__glibc_unlikely (chunksize_nomask (next) < 2 * SIZE_SZ)
              || __glibc_unlikely (chunksize_nomask (next) > av->system_mem))
            malloc_printerr ("malloc(): invalid next size (unsorted)");
          if (__glibc_unlikely ((prev_size (next) & ~(SIZE_BITS)) != size))
            malloc_printerr ("malloc(): mismatching next->prev_size (unsorted)");
          if (__glibc_unlikely (bck->fd != victim)
              || __glibc_unlikely (victim->fd != unsorted_chunks (av)))
            malloc_printerr ("malloc(): unsorted double linked list corrupted");
          if (__glibc_unlikely (prev_inuse (next)))
            malloc_printerr ("malloc(): invalid next->prev_inuse (unsorted)");
           /* 进行安全检测
              1. 检测当前chunk大小是否合法
              2. 检测与当前chunk相邻的后一个chunk的大小是否合法
              3. 检测当前chunk的大小或相邻的后一个chunk的prev_size段是否被修改
              4. 检测双链表结构是否被破坏(防止unsorted bin的指针被修改)
              5. 检测相邻的后一个chunk的inuse位是否为0(如果为1则表示后面的chunk被修改了)
           */

          if (in_smallbin_range (nb) &&
              bck == unsorted_chunks (av) &&
              victim == av->last_remainder &&
              (unsigned long) (size) > (unsigned long) (nb + MINSIZE))
            { /* 
                 1. 用户申请的chunk大小符合small bin 
                 2. unsorted bin中只有一个chunk时
                 3. 当前的chunk是由之前的chunk分裂后生成的
                 4. 当前的chunk分裂出用户申请的chunk后，还可以生成至少一个chunk
                 */
              remainder_size = size - nb;
              remainder = chunk_at_offset (victim, nb);
              unsorted_chunks (av)->bk = unsorted_chunks (av)->fd = remainder;
              av->last_remainder = remainder;
              remainder->bk = remainder->fd = unsorted_chunks (av);
              if (!in_smallbin_range (remainder_size))
                {
                  remainder->fd_nextsize = NULL;
                  remainder->bk_nextsize = NULL;
                  /* 当分裂后剩余的chunk 符合large bin的范围时，
                      为将chunk放入large bin中做好准备 */
                }
              set_head (victim, nb | PREV_INUSE |
                        (av != &main_arena ? NON_MAIN_ARENA : 0));
              set_head (remainder, remainder_size | PREV_INUSE);
              set_foot (remainder, remainder_size);
              check_malloced_chunk (av, victim, nb);
              void *p = chunk2mem (victim);
              alloc_perturb (p, bytes);
              /* 设置分裂后剩余的chunk的头部，并对返回给用户的chunk进行安全检测与data初始化操作 */
              return p;
            }
          if (__glibc_unlikely (bck->fd != victim))
            malloc_printerr ("malloc(): corrupted unsorted chunks 3");
            /* 再次检测双链表完整性，防止unsorted bin中的chunk被修改 */
          unsorted_chunks (av)->bk = bck;
          bck->fd = unsorted_chunks (av); 
            /* 将当前chunk从unsorted bin中取出
                将其放入相应的bin中 */

          if (size == nb)
            { /* 当chunk的大小符合用户申请的大小时，
                  如果对应的tcache bin中没有填满，则先将chunk放入tcache bin中
                  如果填满了，就设置好chunk的头部，将其返回给用户 */
              set_inuse_bit_at_offset (victim, size);
              if (av != &main_arena)
		set_non_main_arena (victim);
#if USE_TCACHE
	      if (tcache_nb
		  && tcache->counts[tc_idx] < mp_.tcache_count)
		{
		  tcache_put (victim, tc_idx);
		  return_cached = 1; /* 设置状态变量，在遍历unsorted bin之后，从tcache bin中获取chunk
                              防止资源浪费 */
		  continue;
		}
	      else
		{
#endif
              check_malloced_chunk (av, victim, nb);
              void *p = chunk2mem (victim);
              alloc_perturb (p, bytes);
              return p;
#if USE_TCACHE
		}
#endif
            }
          if (in_smallbin_range (size))
            { /* 当chunk符合small bin的范围时，准备好将其放入small bin 
                  获取对应的small bin编号，并获取small bin中结尾的chunk，
                  用于将当前chunk添加进small bin */
              victim_index = smallbin_index (size);
              bck = bin_at (av, victim_index);
              fwd = bck->fd;
            }
          else
            {
              /* 当chunk符合large bin的范围时，准备好将其放入large bin
                  获取对应的large bin编号，获取对应bin的最后一个chunk*/
              victim_index = largebin_index (size);
              bck = bin_at (av, victim_index);
              fwd = bck->fd;
              if (fwd != bck)
                { /* 当bin中存在成员时 */
                  size |= PREV_INUSE;
                  assert (chunk_main_arena (bck->bk)); 
                    /* 当chunk不是通过主分配区分配则中断程序*/
                  if ((unsigned long) (size)
		      < (unsigned long) chunksize_nomask (bck->bk))
                    { /* 因为bck->bk 指向的是第一个chunk，
                          在large bin中第一个chunk就是当前bin中最小的chunk
                          如果当前chunk的大小比当前bin中最小的chunk还小
                          就准备将当前chunk插入large bin的开头，
                          并将其加入size_bin中 */
                      fwd = bck;
                      bck = bck->bk;
                      victim->fd_nextsize = fwd->fd;
                      victim->bk_nextsize = fwd->fd->bk_nextsize;
                      fwd->fd->bk_nextsize = victim->bk_nextsize->fd_nextsize = victim;
                  /* 这里没有检测size_bin是否完整，
                      所以只要原先在large bin中存在一个较大chunk，
                      并且设置chunk中bk_nextsize字段为内存中的地址，
                      然后再从unsorted bin向large bin放入一个大小较小的chunk
                      就会向 原先指定的内存中的地址+0x20位置处 写入一个堆块地址 */

                    }
                  else
                    {
                      assert (chunk_main_arena (fwd));
                      /* 限制chunk必须属于主分配区，这里是防止bin被修改 */ 
                      while ((unsigned long) size < chunksize_nomask (fwd))
                        {
                          fwd = fwd->fd_nextsize;
			  assert (chunk_main_arena (fwd));
                          /* 利用size_bin获取large bin中第一个比当前chunk小的成员 
                            这样就可以找到一个 a<= ?? <b 的位置*/
                        }
                      if ((unsigned long) size
			  == (unsigned long) chunksize_nomask (fwd))  
        /*如果当前chunk与找到的size_bin的第一个成员大小相同，
            则将当前chunk插入到找到的size_bin节点在large bin中的位置的前面*/

                        fwd = fwd->fd;
                      else
                        {
                          /* 这种情况就是 a< ?? < b
                            所以在 size_bin中创建一个节点，在找到的节点后面
                            并将当前chunk插入到找到的size_bin节点在large bin中位置的后面*/
                          victim->fd_nextsize = fwd;
                          victim->bk_nextsize = fwd->bk_nextsize;
                          if (__glibc_unlikely (fwd->bk_nextsize->fd_nextsize != fwd))
                            malloc_printerr ("malloc(): largebin double linked list corrupted (nextsize)");
                            /* 检测size_bin完整性 */
                          fwd->bk_nextsize = victim;
                          victim->bk_nextsize->fd_nextsize = victim;
                        }
                      bck = fwd->bk;
                      if (bck->fd != fwd)
                        malloc_printerr ("malloc(): largebin double linked list corrupted (bk)");
                    }
                }
              else
                victim->fd_nextsize = victim->bk_nextsize = victim;
                /* 当bin中不存在成员时，直接设置好chunk所属的size_bin，
                  size_bin属于当前large bin，用来快速找到当前bin中下一个较大的chunk*/
            }
          mark_bin (av, victim_index);
          victim->bk = bck;
          victim->fd = fwd;
          fwd->bk = victim;
          bck->fd = victim;
          /* 这里是真正将chunk放入small bin或large bin */

#if USE_TCACHE
      ++tcache_unsorted_count;
      if (return_cached
	  && mp_.tcache_unsorted_limit > 0
	  && tcache_unsorted_count > mp_.tcache_unsorted_limit)
	{ /* 如果在执行上面的代码时 将unsorted bin中的chunk放入了tcache bin
        且tcache 设置了遍历unsorted bin获取chunk的阈值
        遍历unsorted bin中的chunk数量已经超过阈值，
        则直接将刚刚放入tcache bin中的chunk返回给用户*/
	  return tcache_get (tc_idx);
	}
#endif
#define MAX_ITERS       10000
          if (++iters >= MAX_ITERS)
            break; /* 限制循环次数 防止死循环*/
        }
#if USE_TCACHE
      if (return_cached)
	{ /* 如果上面的代码 从unsorted bin中取出chunk，
        并将其放入tcache bin中，则从tcache bin中取出chunk并返回给用户*/
	  return tcache_get (tc_idx);
	}
#endif
      if (!in_smallbin_range (nb))
        { /* 当用户申请的chunk大小符合large bin的范围时 */

          bin = bin_at (av, idx);
          if ((victim = first (bin)) != bin
	      && (unsigned long) chunksize_nomask (victim)
	        >= (unsigned long) (nb))
            { /* 在大循环执行获取的用户申请的chunk的大小对应的large bin的编号在这里用上了
                   在链表中 bin本身的fd指针指向的是bin中最后一个成员
                                    bk指针指向的是bin中第一个成员
                   所以这里是确认找到的bin中存在 符合用户申请的大小 的chunk
                  (因为large bins中每个bin都不是只能储存一种大小的chunk
                     所以在 符合条件的bin 中存在比 申请的大小大的chunk) */

              victim = victim->bk_nextsize; 

              /*从前面将unsorted bin中的chunk放入large bin的代码可以看出
                  large bin中最后一个节点 也是对应的 size_bin的最后一个节点 
                因为victim是最大的，所以victim->bk_nextsize就是size_bin中最小的chunk */
              while (((unsigned long) (size = chunksize (victim)) <
                      (unsigned long) (nb)))
                victim = victim->bk_nextsize;
                /* 搜索当前bin，找到第一个符合用户申请大小的chunk */

              if (victim != last (bin)
		  && chunksize_nomask (victim)
		    == chunksize_nomask (victim->fd))
                victim = victim->fd;
              /* 当搜索到的size_bin的节点不是当前bin中第一个成员
                  且在当前bin中与找到的节点大小相同的chunk不止一个
                   将 其他的大小与找到的节点相同的chunk 返回给用户
                  为防止频繁改动size_bin，非必要情况下一般不使用size_bin的节点创建chunk*/

              remainder_size = size - nb;
              unlink_chunk (av, victim); 
                /* 先将要返回给用户的chunk从bin中分离出来 */
              if (remainder_size < MINSIZE)
                { /* 如果将找到的chunk分裂之后无法再生成一个chunk
                      则直接将找到的chunk返回给用户 */

                  set_inuse_bit_at_offset (victim, size);
                  if (av != &main_arena)
		    set_non_main_arena (victim);
                }
              else
                {
                  /* 将找到的chunk分裂，并将剩余空间设置为一个新的chunk放入unsorted bin中 */
                  remainder = chunk_at_offset (victim, nb);
                  bck = unsorted_chunks (av);
                  fwd = bck->fd;
		  if (__glibc_unlikely (fwd->bk != bck))
		    malloc_printerr ("malloc(): corrupted unsorted chunks");
                  remainder->bk = bck;
                  remainder->fd = fwd;
                  bck->fd = remainder;
                  fwd->bk = remainder;
                  if (!in_smallbin_range (remainder_size))
                    {
                      remainder->fd_nextsize = NULL;
                      remainder->bk_nextsize = NULL;
                    }
                  set_head (victim, nb | PREV_INUSE |
                            (av != &main_arena ? NON_MAIN_ARENA : 0));
                  set_head (remainder, remainder_size | PREV_INUSE);
                  set_foot (remainder, remainder_size);
                }
              check_malloced_chunk (av, victim, nb);
              void *p = chunk2mem (victim);
              alloc_perturb (p, bytes);
              /* 对chunk进行检测，并进行初始化操作之后返回给用户 */
              return p;
            }
        }
      ++idx;
      bin = bin_at (av, idx);
      block = idx2block (idx);
      map = av->binmap[block];
      bit = idx2bit (idx);
      /* 在上面的代码中搜索了所有刚好符合 用户申请大小条件的bin
          这里先获取 符合用户申请大小条件的 一组 bin 与 bin 在这一组中的索引
          在下面的代码会搜索所有bin，除非找不到符合条件chunk*/
      for (;; )
        {
          if (bit > map || bit == 0)
            {
              do
                {
                  if (++block >= BINMAPSIZE)
                    goto use_top;
                    /* 先尝试搜索一组有成员的bin，如果找不到就使用top chunk分裂获取*/
                }
              while ((map = av->binmap[block]) == 0);
              bin = bin_at (av, (block << BINMAPSHIFT));
              bit = 1; 
            }
          while ((bit & map) == 0)
            {
              /* 在上面的do...while循环中已经找到一组肯定存在成员的bin
                现在是要精确找到存在成员的bin 
                 bit==0 就表示程序流被控制了*/
              bin = next_bin (bin);
              bit <<= 1;
              assert (bit != 0);
            }
          victim = last (bin);
          if (victim == bin)
            { /* 如果找到的bin中实际上没有chunk
                  则表示 在获取 binmap的值没有更新
                  这里更新一下map，并获取下一个bin，然后进行下一次循环 */
              av->binmap[block] = map &= ~bit;
              bin = next_bin (bin);
              bit <<= 1;
            }
          else
            {
              size = chunksize (victim);
              assert ((unsigned long) (size) >= (unsigned long) (nb));
              /* 如果这里找到的chunk的大小小于用户申请的大小，则表示chunk被恶意修改了 */
              remainder_size = size - nb;
              unlink_chunk (av, victim);
               /* 将找到的chunk从对应的bin中分离出来 */
              if (remainder_size < MINSIZE)
                {
                  set_inuse_bit_at_offset (victim, size);
                  if (av != &main_arena)
		    set_non_main_arena (victim);
                    /* 如果分裂后剩余空间无法生成一个完整的chunk，
                        则直接将整个chunk返回给用户 */
                }
              else
                {
                  /* 将chunk分裂，并将分裂后剩余空间设置为一个新的chunk放入unsorted bin中*/
                  remainder = chunk_at_offset (victim, nb);
                  bck = unsorted_chunks (av);
                  fwd = bck->fd;
		  if (__glibc_unlikely (fwd->bk != bck))
		    malloc_printerr ("malloc(): corrupted unsorted chunks 2");
                    /* 检测双链表完整性 */
                  remainder->bk = bck;
                  remainder->fd = fwd;
                  bck->fd = remainder;
                  fwd->bk = remainder;
                  if (in_smallbin_range (nb))
                    av->last_remainder = remainder;
                  if (!in_smallbin_range (remainder_size))
                    {
                      remainder->fd_nextsize = NULL;
                      remainder->bk_nextsize = NULL;
                      /* 如果分裂后剩余空间符合large bin的条件，则初始化fd_nextsize,bk_nextsize */
                    }
                  set_head (victim, nb | PREV_INUSE |
                            (av != &main_arena ? NON_MAIN_ARENA : 0));
                  set_head (remainder, remainder_size | PREV_INUSE);
                  set_foot (remainder, remainder_size);
                }
              check_malloced_chunk (av, victim, nb);
              void *p = chunk2mem (victim);
              alloc_perturb (p, bytes);
              /* 设置好chunk的标志，并进行检测与初始化data的操作，然后将chunk返回给用户 */
              return p;
            }
        }
    use_top:
      /* 当上面的操作都无法获取chunk，则尝试通过分裂top chunk获取chunk */
      victim = av->top;
      size = chunksize (victim);
      if (__glibc_unlikely (size > av->system_mem))
        malloc_printerr ("malloc(): corrupted top size");
        /* 检测top chunk的大小是否过大，这种情况一般是top chunk的size被恶意修改了 */
      if ((unsigned long) (size) >= (unsigned long) (nb + MINSIZE))
        { /* 当top chunk分裂出用户申请的chunk之后还可以生成一个完整的chunk时 */
          remainder_size = size - nb;
          remainder = chunk_at_offset (victim, nb);
          av->top = remainder;
          set_head (victim, nb | PREV_INUSE |
                    (av != &main_arena ? NON_MAIN_ARENA : 0));
          set_head (remainder, remainder_size | PREV_INUSE);
          check_malloced_chunk (av, victim, nb);
          void *p = chunk2mem (victim); /* 获取chunk的data字段地址*/
          alloc_perturb (p, bytes);
          /* 从top chunk分裂出chunk之后，为chunk设置头部，并进行安全检测与初始化data操作
             然后将chunk返回给用户 */
          return p;
        }
      else if (atomic_load_relaxed (&av->have_fastchunks))
        {
          malloc_consolidate (av);
          if (in_smallbin_range (nb))
            idx = smallbin_index (nb);
          else
            idx = largebin_index (nb);
          /* 当fast bin中存在chunk时，合并fast bin中的chunk，并将合并后的chunk放入对应的bin中
              先获取符合用户申请的chunk的bin的编号，然后进入下一次循环 */
        }
      else
        { /* 这种情况就是top chunk没有多余空间用来生成chunk
              且bin中也没有符合条件的chunk
              尝试使用 sysmalloc 从内存中申请空间
               如果原因处在top chunk过小，这个函数就会扩展top chunk */
          void *p = sysmalloc (nb, av);
          if (p != NULL)
            alloc_perturb (p, bytes);
            /* 将获取的chunk初始化后返回给用户*/
          return p;
        }
    }
