static void malloc_consolidate(mstate av)
{
  mfastbinptr*    fb;
  mfastbinptr*    maxfb;
  mchunkptr       p;
  mchunkptr       nextp;
  mchunkptr       unsorted_bin;
  mchunkptr       first_unsorted;
  mchunkptr       nextchunk;
  INTERNAL_SIZE_T size;
  INTERNAL_SIZE_T nextsize;
  INTERNAL_SIZE_T prevsize;
  int             nextinuse;
  atomic_store_relaxed (&av->have_fastchunks, false);
  unsorted_bin = unsorted_chunks(av);
  maxfb = &fastbin (av, NFASTBINS - 1);
  fb = &fastbin (av, 0);
  do {
      /* 遍历所有fast bin */
    p = atomic_exchange_acq (fb, NULL); /* 获取bin中第一个成员*/
    if (p != 0) {
      do {
	{  /* 如果bin中没有成员则跳过 */
	  unsigned int idx = fastbin_index (chunksize (p));
	  if ((&fastbin (av, idx)) != fb)
	    malloc_printerr ("malloc_consolidate(): invalid chunk size");
      /* 如果获取到的chunk的size不属于当前bin，则表示chunk被修改过了 */
	}
	check_inuse_chunk(av, p); /* 检测当前chunk及其附近的chunk的大小和inuse位是否合法 */
	nextp = p->fd;  /* 获取fast bin中下一个成员，为下一次循环做准备 */
	size = chunksize (p);
	nextchunk = chunk_at_offset(p, size);
	nextsize = chunksize(nextchunk);
	if (!prev_inuse(p)) {
    /* 当当前chunk的inuse位为0时，表示前一个chunk属于空闲状态
        合并两个chunk */
	  prevsize = prev_size (p);
	  size += prevsize;
	  p = chunk_at_offset(p, -((long) prevsize));
    /* 如果当前chunk的prev_size字段不等于 前一个chunk的size字段，则表示当前chunk被恶意修改过了*/
	  if (__glibc_unlikely (chunksize(p) != prevsize))
	    malloc_printerr ("corrupted size vs. prev_size in fastbins");
	  unlink_chunk (av, p);
	}
	if (nextchunk != av->top) {
    /* 确保后一个chunk不是top chunk，如果是就直接与top chunk合并  */
	  nextinuse = inuse_bit_at_offset(nextchunk, nextsize);
	  if (!nextinuse) {
	    size += nextsize;
	    unlink_chunk (av, nextchunk);
      /* 如果后一个chunk当前为空闲状态，则将其从所在bin中取出 */
	  } else
	    clear_inuse_bit_at_offset(nextchunk, 0);
	  first_unsorted = unsorted_bin->fd;
	  unsorted_bin->fd = p;
	  first_unsorted->bk = p;
	  if (!in_smallbin_range (size)) {
	    p->fd_nextsize = NULL;
	    p->bk_nextsize = NULL;
	  }
	  set_head(p, size | PREV_INUSE);
	  p->bk = unsorted_bin;
	  p->fd = first_unsorted;
	  set_foot(p, size);
    /* 设置好合并后的chunk头部，并将合并后的chunk放入unsorted bin中 */
	}
	else {
	  size += nextsize;
	  set_head(p, size | PREV_INUSE);
	  av->top = p;
	}
      } while ( (p = nextp) != 0);
    }
  } while (fb++ != maxfb);
}
